  7	  V1VirtualMachineInstanceGuestAgentInfo,
  8	} from '@kubevirt-ui/kubevirt-api/kubevirt';
  9	import CPUMemory from '@kubevirt-utils/components/CPUMemory/CPUMemory';
 10	import GuestAgentIsRequiredText from '@kubevirt-utils/components/GuestAgentIsRequiredText/GuestAgentIsRequiredText';
 11	import { timestampFor } from '@kubevirt-utils/components/Timestamp/utils/datetime';
 12	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 13	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 14	import { TREE_VIEW_FOLDERS } from '@kubevirt-utils/hooks/useFeatures/constants';
 15	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 16	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 17	import { getLabel, getName, getVMStatus } from '@kubevirt-utils/resources/shared';
 18	import { getInstanceTypeMatcher } from '@kubevirt-utils/resources/vm';
 19	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 20	import { getOsNameFromGuestAgent } from '@kubevirt-utils/resources/vmi';
 21	import { isEmpty } from '@kubevirt-utils/utils/utils';
 22	import { Timestamp } from '@openshift-console/dynamic-plugin-sdk';
 23	import {
 24	  Card,
 25	  CardBody,
 26	  CardTitle,
 27	  DescriptionList,
 28	  Divider,
 29	  Grid,
 30	  GridItem,
 31	  pluralize,
 32	  Skeleton,
 33	  Split,
 34	  SplitItem,
 35	} from '@patternfly/react-core';
 36	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
 37	import VMNotMigratableLabel from '@virtualmachines/list/components/VMNotMigratableLabel/VMNotMigratableLabel';
 38	import { VM_FOLDER_LABEL } from '@virtualmachines/tree/utils/constants';
 39	import { printableVMStatus } from '@virtualmachines/utils';
 40	
 41	import InstanceTypeDescription from './components/InstanceTypeDescription';
 42	import TemplateDescription from './components/TemplateDescription';
 43	import VirtualMachineMigrationPercentage from './components/VirtualMachineMigrationPercentage';
 44	import VirtualMachinesOverviewTabDetailsConsole from './components/VirtualMachinesOverviewTabDetailsConsole';
 45	import StatusPopover from './components/VirtualMachineStatusWithPopover/VirtualMachineStatusWithPopover';
 46	
 47	import './virtual-machines-overview-tab-details.scss';
 48	
 49	type VirtualMachinesOverviewTabDetailsProps = {
 50	  error: Error;
 51	  guestAgentData: V1VirtualMachineInstanceGuestAgentInfo;
 52	  guestAgentDataLoaded: boolean;
 53	  instanceTypeExpandedSpec: V1VirtualMachine;
 54	  loaded: boolean;
 55	  vm: V1VirtualMachine;
 56	  vmi: V1VirtualMachineInstance;
 57	};
 58	
 59	const VirtualMachinesOverviewTabDetails: FC<VirtualMachinesOverviewTabDetailsProps> = ({
 60	  error,
 61	  guestAgentData,
 62	  guestAgentDataLoaded,
 63	  instanceTypeExpandedSpec,
 64	  loaded,
 65	  vm,
 66	  vmi,
 67	}) => {
 68	  const { t } = useKubevirtTranslation();
 69	  const { featureEnabled: treeViewFoldersEnabled } = useFeatures(TREE_VIEW_FOLDERS);
 70	
 71	  const timestamp = timestampFor(
 72	    new Date(vm?.metadata?.creationTimestamp),
 73	    new Date(Date.now()),
 74	    true,
 75	  );
 76	
 77	  const timestampPluralized = pluralize(timestamp['value'], timestamp['time']);
 78	
 79	  const { fallback, hostname, osName } = useMemo(() => {
 80	    const isLoadingVMI = !loaded && !error;
 81	    if (!guestAgentDataLoaded || isLoadingVMI)
 82	      return {
 83	        fallback: <Skeleton />,
 84	      };
 85	    if (!isEmpty(guestAgentData))
 86	      return {
 87	        hostname: guestAgentData?.hostname,
 88	        osName: getOsNameFromGuestAgent(guestAgentData),
 89	      };
 90	    return {
 91	      fallback: <GuestAgentIsRequiredText vmi={vmi} />,
 92	    };
 93	  }, [loaded, error, guestAgentDataLoaded, guestAgentData, vmi]);
 94	
 95	  const vmPrintableStatus = getVMStatus(vm);
 96	
 97	  return (
 98	    <div className="VirtualMachinesOverviewTabDetails--details">
 99	      <Card>
100	        <CardTitle className="text-muted card-title">
101	          <Link
102	            to={createURL(
103	              `${VirtualMachineDetailsTab.Configurations}/${VirtualMachineDetailsTab.Details}`,
104	              location?.pathname,
105	            )}
106	          >
107	            {t('Details')}
108	          </Link>
109	        </CardTitle>
110	        <Divider />
111	        <CardBody isFilled>
112	          <Grid>
113	            <GridItem span={5}>
114	              <DescriptionList className="pf-v6-c-description-list" isHorizontal>
115	                <VirtualMachineDescriptionItem
116	                  data-test-id="virtual-machine-overview-details-name"
117	                  descriptionData={getName(vm)}
118	                  descriptionHeader={t('Name')}
119	                />
120	                {treeViewFoldersEnabled && (
121	                  <VirtualMachineDescriptionItem
122	                    data-test-id="virtual-machine-overview-details-folder"
123	                    descriptionData={getLabel(vm, VM_FOLDER_LABEL) || NO_DATA_DASH}
124	                    descriptionHeader={t('Folder')}
125	                  />
126	                )}
127	                <VirtualMachineDescriptionItem
128	                  descriptionData={
129	                    <Split hasGutter isWrappable>
130	                      <SplitItem>
131	                        <StatusPopover vm={vm} vmi={vmi} />
132	                        {vmPrintableStatus === printableVMStatus.Migrating && (
133	                          <VirtualMachineMigrationPercentage vm={vm} />
134	                        )}
135	                      </SplitItem>
136	                      <VMNotMigratableLabel vm={vm} />
137	                    </Split>
138	                  }
139	                  data-test-id="virtual-machine-overview-details-status"
140	                  descriptionHeader={t('Status')}
141	                />
142	                <VirtualMachineDescriptionItem
143	                  descriptionData={
144	                    timestamp !== NO_DATA_DASH ? (
145	                      <>
146	                        <Timestamp simple timestamp={vm?.metadata?.creationTimestamp} /> (
147	                        {t('{{timestampPluralized}} ago', { timestampPluralized })})
148	                      </>
149	                    ) : (
150	                      NO_DATA_DASH
151	                    )
152	                  }
153	                  data-test-id="virtual-machine-overview-details-created"
154	                  descriptionHeader={t('Created')}
155	                />
156	                <VirtualMachineDescriptionItem
157	                  data-test-id="virtual-machine-overview-details-os"
158	                  descriptionData={osName ?? fallback}
159	                  descriptionHeader={t('Operating system')}
160	                />
161	                <VirtualMachineDescriptionItem
162	                  descriptionData={<CPUMemory vm={instanceTypeExpandedSpec || vm} vmi={vmi} />}
163	                  descriptionHeader={t('CPU | Memory')}
164	                />
165	                <VirtualMachineDescriptionItem
166	                  data-test-id="virtual-machine-overview-details-timezone"
167	                  descriptionData={guestAgentData?.timezone?.split(',')[0] || NO_DATA_DASH}
168	                  descriptionHeader={t('Time zone')}
169	                />
170	                {getInstanceTypeMatcher(vm) ? (
171	                  <InstanceTypeDescription vm={vm} />
172	                ) : (
173	                  <TemplateDescription vm={vm} />
174	                )}
175	                <VirtualMachineDescriptionItem
176	                  data-test-id="virtual-machine-overview-details-host"
177	                  descriptionData={hostname ?? fallback}
178	                  descriptionHeader={t('Hostname')}
179	                />
180	              </DescriptionList>
181	            </GridItem>
182	            <GridItem span={1} />
183	            <GridItem span={5}>
184	              <div className="right-column">
185	                <div className="title">{t('VNC console')}</div>
186	                <VirtualMachinesOverviewTabDetailsConsole vmi={vmi} />
187	              </div>
188	            </GridItem>
189	          </Grid>
190	        </CardBody>
191	      </Card>
192	    </div>
193	  );
194	};
195	
196	export default VirtualMachinesOverviewTabDetails;

